        *,
        squash: bool,
        verbose: bool,
        subject: str | None = None,
        body: str | None = None,
    ) -> MergeResult:
        """No-op for merging PR in dry-run mode."""
        # Do nothing - prevents actual PR merge
        return MergeResult(pr_number=pr_number)

    def trigger_workflow(
